  1→//! Nostr relay subscription loop — inbound DM pipeline.
  2→//!
  3→//! Subscribes to kind:4 (NIP-04 encrypted DMs) addressed to the bot's pubkey.
  4→//! Events flow through dedup, self-message filtering, access control, and
  5→//! decryption before being dispatched to the gateway via `ChannelEventSink`.
  6→
  7→use std::sync::{Arc, RwLock};
  8→
  9→use {
 10→    nostr_sdk::prelude::{
 11→        Client, Event, Filter, Keys, Kind, PublicKey, RelayPoolNotification, Timestamp, ToBech32,
 12→        nip04, nip44,
 13→    },
 14→    tokio_util::sync::CancellationToken,
 15→};
 16→
 17→use crate::{
 18→    access::{self, AccessDenied},
 19→    config::NostrAccountConfig,
 20→    seen::SeenTracker,
 21→    state::SharedOtp,
 22→};
 23→
 24→#[cfg(feature = "metrics")]
 25→use moltis_metrics::{counter, nostr as nostr_metrics};
 26→
 27→/// Maximum plaintext message size in bytes.
 28→const MAX_MESSAGE_BYTES: usize = 64 * 1024;
 29→
 30→/// Message sent to non-allowlisted senders as an OTP challenge prompt.
 31→const OTP_CHALLENGE_MSG: &str = "You are not on the allowlist. A PIN challenge has been sent to the admin. Reply with the 6-digit code to gain access.";
 32→
 33→/// Run the relay subscription loop for a single Nostr account.
 34→///
 35→/// Subscribes to NIP-04 DMs (kind:4) targeted at `bot_pubkey` and dispatches
 36→/// inbound messages to the gateway. Runs until `cancel` is triggered or the
 37→/// relay pool shuts down (which triggers an auto-disable request).
 38→pub async fn run_subscription_loop(
 39→    client: Client,
 40→    keys: Keys,
 41→    config: Arc<RwLock<NostrAccountConfig>>,
 42→    cached_allowlist: Arc<RwLock<Vec<PublicKey>>>,
 43→    otp: SharedOtp,
 44→    account_id: String,
 45→    event_sink: Arc<dyn moltis_channels::ChannelEventSink>,
 46→    cancel: CancellationToken,
 47→) {
 48→    let bot_pubkey = keys.public_key();
 49→    let now_secs =
 50→        u64::try_from(::time::OffsetDateTime::now_utc().unix_timestamp()).unwrap_or_default();
 51→    let since = Timestamp::from(now_secs);
 52→
 53→    let filter = Filter::new()
 54→        .kind(Kind::EncryptedDirectMessage)
 55→        .pubkey(bot_pubkey)
 56→        .since(since);
 57→
 58→    let npub = bot_pubkey
 59→        .to_bech32()
 60→        .unwrap_or_else(|_| bot_pubkey.to_hex());
 61→    tracing::info!(
 62→        account_id,
 63→        pubkey = %npub,
 64→        "starting Nostr DM subscription"
 65→    );
 66→
 67→    let mut seen = SeenTracker::new();
 68→
 69→    // Subscribe (single filter)
 70→    if let Err(e) = client.subscribe(filter, None).await {
 71→        tracing::error!(account_id, "failed to subscribe: {e}");
 72→        return;
 73→    }
 74→
 75→    let mut notifications = client.notifications();
 76→
 77→    loop {
 78→        tokio::select! {
 79→            () = cancel.cancelled() => {
 80→                tracing::info!(account_id, "Nostr subscription cancelled");
 81→                break;
 82→            }
 83→            notification = notifications.recv() => {
 84→                match notification {
 85→                    Ok(RelayPoolNotification::Event { event, .. }) => {
 86→                        handle_event(
 87→                            &event,
 88→                            &client,
 89→                            &keys,
 90→                            &bot_pubkey,
 91→                            since,
 92→                            &mut seen,
 93→                            &config,
 94→                            &cached_allowlist,
 95→                            &otp,
 96→                            &account_id,
 97→                            &event_sink,
 98→                        ).await;
 99→                    }
100→                    Ok(RelayPoolNotification::Shutdown) => {
101→                        tracing::warn!(account_id, "relay pool shutdown — requesting account disable");
102→                        event_sink
103→                            .request_disable_account("nostr", &account_id, "relay pool shutdown")
104→                            .await;
105→                        break;
106→                    }
107→                    Ok(_) => {}
108→                    Err(e) => {
109→                        tracing::warn!(account_id, "notification channel error: {e}");
110→                    }
111→                }
112→            }
113→        }
114→    }
115→
116→    tracing::info!(account_id, "Nostr subscription loop exited");
117→}
118→
119→/// Process a single inbound event through the pipeline.
120→#[allow(clippy::too_many_arguments)]
121→async fn handle_event(
122→    event: &Event,
123→    client: &Client,
124→    keys: &Keys,
125→    bot_pubkey: &PublicKey,
126→    since: Timestamp,
127→    seen: &mut SeenTracker,
128→    config: &Arc<RwLock<NostrAccountConfig>>,
129→    cached_allowlist: &Arc<RwLock<Vec<PublicKey>>>,
130→    otp: &SharedOtp,
131→    account_id: &str,
132→    event_sink: &Arc<dyn moltis_channels::ChannelEventSink>,
133→) {
134→    // 1. Skip non-DM events
135→    if event.kind != Kind::EncryptedDirectMessage {
136→        return;
137→    }
138→
139→    // 2. Dedup check
140→    if seen.check_and_insert(&event.id) {
141→        return;
142→    }
143→
144→    // 3. Skip self-messages
145→    if event.pubkey == *bot_pubkey {
146→        return;
147→    }
148→
149→    // 4. Skip stale events
150→    if event.created_at < since {
151→        return;
152→    }
153→
154→    let sender_hex = event.pubkey.to_hex();
155→    let sender_npub = event
156→        .pubkey
157→        .to_bech32()
158→        .unwrap_or_else(|_| sender_hex.clone());
159→
160→    // 5. Read config fields (drop guard before any .await).
161→    let (dm_policy, otp_self_approval) = {
162→        let cfg = config.read().unwrap_or_else(|e| e.into_inner());
163→        (cfg.dm_policy.clone(), cfg.otp_self_approval)
164→    };
165→
166→    // 5a. OTP verification — if this sender has a pending challenge, decrypt
167→    //     first to check if the message is a 6-digit code, and verify it.
168→    //     This must run BEFORE the access-control gate because the sender is
169→    //     not yet on the allowlist when they reply with the OTP code.
170→    let has_pending = {
171→        let guard = otp.lock().unwrap_or_else(|e| e.into_inner());
172→        guard.has_pending(&sender_hex)
173→    };
174→    if has_pending {
175→        if let Some(plaintext) = try_decrypt(keys, &event.pubkey, &event.content) {
176→            let trimmed = plaintext.trim();
177→            if trimmed.len() == 6 && trimmed.chars().all(|c| c.is_ascii_digit()) {
178→                handle_otp_verification(
179→                    otp,
180→                    client,
181→                    keys,
182→                    &event.pubkey,
183→                    account_id,
184→                    &sender_hex,
185→                    &sender_npub,
186→                    trimmed,
187→                    event_sink,
188→                )
189→                .await;
190→                return;
191→            }
192→        }
193→        // Non-code reply while challenge pending — silently ignore.
194→        return;
195→    }
196→
197→    // 5b. Normal access-control gate (scope the guard so it drops before any .await).
198→    let access_result = {
199→        let allowed = cached_allowlist.read().unwrap_or_else(|e| e.into_inner());
200→        access::check_dm_access(&event.pubkey, &dm_policy, &allowed)
201→    };
202→
203→    match &access_result {
204→        Ok(()) => {},
205→        Err(AccessDenied::Disabled) => {
206→            #[cfg(feature = "metrics")]
207→            counter!(nostr_metrics::ACCESS_CONTROL_DENIALS_TOTAL, "reason" => "disabled")
208→                .increment(1);
209→            tracing::debug!(account_id, sender = sender_hex, "DM rejected: disabled");
210→            return;
211→        },
212→        Err(AccessDenied::NotAllowlisted) => {
213→            #[cfg(feature = "metrics")]
214→            counter!(nostr_metrics::ACCESS_CONTROL_DENIALS_TOTAL, "reason" => "not_allowlisted")
215→                .increment(1);
216→            if otp_self_approval {
217→                handle_otp_challenge(
218→                    client,
219→                    keys,
220→                    &event.pubkey,
221→                    otp,
222→                    account_id,
223→                    &sender_hex,
224→                    &sender_npub,
225→                    event_sink,
226→                )
227→                .await;
228→            } else {
229→                tracing::debug!(
230→                    account_id,
231→                    sender = sender_hex,
232→                    "DM rejected: not allowlisted"
233→                );
234→            }
235→            return;
236→        },
237→    }
238→
239→    // 6. Decrypt content — try NIP-04 first, fall back to NIP-44
240→    let plaintext = match nip04::decrypt(keys.secret_key(), &event.pubkey, &event.content) {
241→        Ok(text) => text,
242→        Err(_nip04_err) => match nip44::decrypt(keys.secret_key(), &event.pubkey, &event.content) {
243→            Ok(text) => text,
244→            Err(nip44_err) => {
245→                #[cfg(feature = "metrics")]
246→                counter!(nostr_metrics::DECRYPT_ERRORS_TOTAL).increment(1);
247→                tracing::warn!(
248→                    account_id,
249→                    event_id = %event.id,
250→                    "decrypt failed (NIP-04 and NIP-44): {nip44_err}"
251→                );
252→                return;
253→            },
254→        },
255→    };
256→
257→    // 7. Size validation — truncate at a safe UTF-8 boundary
258→    let text = if plaintext.len() > MAX_MESSAGE_BYTES {
259→        tracing::warn!(account_id, len = plaintext.len(), "DM exceeds size limit");
260→        &plaintext[..plaintext.floor_char_boundary(MAX_MESSAGE_BYTES)]
261→    } else {
262→        &plaintext
263→    };
264→
265→    // 8. Emit inbound event
266→    #[cfg(feature = "metrics")]
267→    counter!(nostr_metrics::MESSAGES_RECEIVED_TOTAL).increment(1);
268→
269→    event_sink
270→        .emit(moltis_channels::ChannelEvent::InboundMessage {
271→            channel_type: moltis_channels::ChannelType::Nostr,
272→            account_id: account_id.to_string(),
273→            peer_id: sender_hex.clone(),
274→            username: Some(sender_npub.clone()),
275→            sender_name: None,
276→            message_count: None,
277→            access_granted: true,
278→        })
279→        .await;
280→
281→    // 9. Dispatch to gateway
282→    let meta = moltis_channels::ChannelMessageMeta {
283→        channel_type: moltis_channels::ChannelType::Nostr,
284→        sender_name: None,
285→        username: Some(sender_npub),
286→        sender_id: Some(sender_hex.clone()),
287→        message_kind: Some(moltis_channels::ChannelMessageKind::Text),
288→        model: None,
289→        agent_id: None,
290→        audio_filename: None,
291→        documents: None,
292→    };
293→
294→    let reply_to = moltis_channels::ChannelReplyTarget {
295→        channel_type: moltis_channels::ChannelType::Nostr,
296→        account_id: account_id.to_string(),
297→        chat_id: sender_hex,
298→        message_id: Some(event.id.to_hex()),
299→        thread_id: None,
300→    };
301→
302→    event_sink.dispatch_to_chat(text, reply_to, meta).await;
303→}
304→
305→/// Try to decrypt a DM (NIP-04, then NIP-44). Returns `None` on failure.
306→fn try_decrypt(keys: &Keys, sender: &PublicKey, content: &str) -> Option<String> {
307→    nip04::decrypt(keys.secret_key(), sender, content)
308→        .ok()
309→        .or_else(|| nip44::decrypt(keys.secret_key(), sender, content).ok())
310→}
311→
312→/// Handle an OTP verification reply (sender sent a 6-digit code).
313→#[allow(clippy::too_many_arguments)]
314→async fn handle_otp_verification(
315→    otp: &SharedOtp,
316→    client: &Client,
317→    keys: &Keys,
318→    sender_pubkey: &PublicKey,
319→    account_id: &str,
320→    sender_hex: &str,
321→    sender_npub: &str,
322→    code: &str,
323→    event_sink: &Arc<dyn moltis_channels::ChannelEventSink>,
324→) {
325→    use moltis_channels::otp::{OtpVerifyResult, emit_otp_resolution};
326→
327→    let result = {
328→        let mut guard = otp.lock().unwrap_or_else(|e| e.into_inner());
329→        guard.verify(sender_hex, code)
330→    };
331→
332→    let (reply_text, resolution) = match result {
333→        OtpVerifyResult::Approved => {
334→            // Request the gateway to add this sender to the approved list.
335→            event_sink
336→                .request_sender_approval("nostr", account_id, sender_hex)
337→                .await;
338→            ("Access granted. You can now send messages.", "approved")
339→        },
340→        OtpVerifyResult::WrongCode { attempts_left } => (
341→            if attempts_left > 0 {
342→                "Wrong code. Please try again."
343→            } else {
344→                "Too many failed attempts. You are temporarily locked out."
345→            },
346→            "wrong_code",
347→        ),
348→        OtpVerifyResult::LockedOut => (
349→            "Too many failed attempts. You are temporarily locked out.",
350→            "locked_out",
351→        ),
352→        OtpVerifyResult::NoPending => ("No pending challenge.", "no_pending"),
353→        OtpVerifyResult::Expired => (
354→            "Challenge expired. Send another message to get a new code.",
355→            "expired",
356→        ),
357→    };
358→
359→    // Send the reply to the sender.
360→    if let Ok(encrypted) = nip04::encrypt(keys.secret_key(), sender_pubkey, reply_text) {
361→        let tag = nostr_sdk::prelude::Tag::public_key(*sender_pubkey);
362→        let builder =
363→            nostr_sdk::prelude::EventBuilder::new(Kind::EncryptedDirectMessage, &encrypted)
364→                .tag(tag);
365→        if let Err(e) = client.send_event_builder(builder).await {
366→            tracing::warn!(account_id, "failed to send OTP verification reply: {e}");
367→        }
368→    }
369→
370→    // Emit resolution event for admin UI.
371→    emit_otp_resolution(
372→        Some(event_sink.as_ref()),
373→        moltis_channels::ChannelType::Nostr,
374→        account_id,
375→        sender_hex,
376→        Some(sender_npub),
377→        resolution,
378→    )
379→    .await;
380→}
381→
382→/// Initiate an OTP challenge for a non-allowlisted sender.
383→///
384→/// Generates a 6-digit code via `OtpState::initiate()`, sends the challenge
385→/// prompt to the sender as an encrypted DM, and emits an `OtpChallenge` event
386→/// for the admin web UI.
387→#[allow(clippy::too_many_arguments)]
388→async fn handle_otp_challenge(
389→    client: &Client,
390→    keys: &Keys,
391→    sender_pubkey: &PublicKey,
392→    otp: &SharedOtp,
393→    account_id: &str,
394→    sender_hex: &str,
395→    sender_npub: &str,
396→    event_sink: &Arc<dyn moltis_channels::ChannelEventSink>,
397→) {
398→    use moltis_channels::otp::{OtpInitResult, emit_otp_challenge};
399→
400→    let init_result = {
401→        let mut otp_guard = otp.lock().unwrap_or_else(|e| e.into_inner());
402→        otp_guard.initiate(sender_hex, Some(sender_npub.to_string()), None)
403→    };
404→
405→    match init_result {
406→        OtpInitResult::Created(code) => {
407→            // Send challenge prompt to the sender via encrypted DM.
408→            if let Ok(encrypted) =
409→                nip04::encrypt(keys.secret_key(), sender_pubkey, OTP_CHALLENGE_MSG)
410→            {
411→                let tag = nostr_sdk::prelude::Tag::public_key(*sender_pubkey);
412→                let builder =
413→                    nostr_sdk::prelude::EventBuilder::new(Kind::EncryptedDirectMessage, &encrypted)
414→                        .tag(tag);
415→                if let Err(e) = client.send_event_builder(builder).await {
416→                    tracing::warn!(account_id, "failed to send OTP challenge DM: {e}");
417→                }
418→            }
419→
420→            // Emit OTP challenge event for the admin UI.
421→            let expires_at = ::time::OffsetDateTime::now_utc().unix_timestamp() + 300;
422→
423→            emit_otp_challenge(
424→                Some(event_sink.as_ref()),
425→                moltis_channels::ChannelType::Nostr,
426→                account_id,
427→                sender_hex,
428→                Some(sender_npub),
429→                None,
430→                code,
431→                expires_at,
432→            )
433→            .await;
434→
435→            #[cfg(feature = "metrics")]
436→            counter!(nostr_metrics::OTP_CHALLENGES_TOTAL).increment(1);
437→        },
438→        OtpInitResult::AlreadyPending | OtpInitResult::LockedOut => {
439→            // Silent — don't spam the sender.
440→        },
441→    }
442→
443→    // Always emit InboundMessage with access_granted: false for the UI.
444→    event_sink
445→        .emit(moltis_channels::ChannelEvent::InboundMessage {
446→            channel_type: moltis_channels::ChannelType::Nostr,
447→            account_id: account_id.to_string(),
448→            peer_id: sender_hex.to_string(),
449→            username: Some(sender_npub.to_string()),
450→            sender_name: None,
451→            message_count: None,
452→            access_granted: false,
453→        })
454→        .await;
455→}
456→
457→#[cfg(test)]
458→mod tests {
459→    use super::*;
460→
461→    #[test]
462→    fn max_message_size_is_reasonable() {
463→        assert_eq!(MAX_MESSAGE_BYTES, 64 * 1024);
464→    }
465→}
466→

