 3→#[derive(Debug, thiserror::Error)]
 4→pub enum Error {
 5→    #[error("nostr SDK error: {0}")]
 6→    Sdk(#[from] nostr_sdk::client::Error),
 7→
 8→    #[error("nostr key error: {0}")]
 9→    Key(#[from] nostr_sdk::prelude::key::Error),
10→
11→    #[error("invalid config: {0}")]
12→    Config(String),
13→
14→    #[error("relay error: {0}")]
15→    Relay(String),
16→
17→    #[error("encryption error: {0}")]
18→    Encryption(String),
19→
20→    #[error("event not found: {0}")]
21→    NotFound(String),
22→}
23→
24→impl Error {
25→    /// Whether this error is transient and the operation may succeed on retry.
26→    #[must_use]
27→    pub fn is_retryable(&self) -> bool {
28→        matches!(self, Self::Sdk(_) | Self::Relay(_))
29→    }
30→}
31→
32→impl From<Error> for ChannelError {
33→    fn from(e: Error) -> Self {
34→        match e {
35→            Error::Config(msg) => ChannelError::invalid_input(msg),
36→            Error::NotFound(id) => ChannelError::unavailable(format!("event not found: {id}")),
37→            other => ChannelError::external("nostr", other),
38→        }
39→    }
40→}
