 40→
 41→impl fmt::Display for Error {
 42→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 43→        match self {
 44→            Self::Signer(e) => e.fmt(f),
 45→            Self::Event(e) => e.fmt(f),
 46→            Self::NotGiftWrap => f.write_str("Not a Gift Wrap"),
 47→            Self::SenderMismatch => f.write_str("sender public key mismatch"),
 48→        }
 49→    }
 50→}
 51→
 52→impl From<SignerError> for Error {
 53→    fn from(e: SignerError) -> Self {
 54→        Self::Signer(e)
 55→    }
 56→}
