 58→impl From<event::Error> for Error {
 59→    fn from(e: event::Error) -> Self {
 60→        Self::Event(e)
 61→    }
 62→}
 63→
 64→/// Unwrapped Gift Wrap (NIP59)
 65→#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
 66→pub struct UnwrappedGift {
 67→    /// The public key of the sender included in the `seal`
 68→    pub sender: PublicKey,
 69→    /// The rumor
 70→    pub rumor: UnsignedEvent,
 71→}
 72→
 73→impl UnwrappedGift {
 74→    /// Unwrap Gift Wrap event
 75→    ///
 76→    /// Internally verify the `seal` event
 77→    #[inline]
 78→    #[cfg(feature = "std")]
 79→    pub async fn from_gift_wrap<T>(signer: &T, gift_wrap: &Event) -> Result<Self, Error>
 80→    where
 81→        T: NostrSigner,
 82→    {
 83→        Self::from_gift_wrap_with_ctx(SECP256K1, signer, gift_wrap).await
 84→    }
 85→
 86→    /// Unwrap Gift Wrap event
 87→    ///
 88→    /// Internally verify the `seal` event
 89→    pub async fn from_gift_wrap_with_ctx<C, T>(
 90→        secp: &Secp256k1<C>,
 91→        signer: &T,
 92→        gift_wrap: &Event,
 93→    ) -> Result<Self, Error>
 94→    where
 95→        C: Verification,
 96→        T: NostrSigner,
 97→    {
 98→        // Check event kind
 99→        if gift_wrap.kind != Kind::GiftWrap {
100→            return Err(Error::NotGiftWrap);
101→        }
102→
103→        // Decrypt and verify seal
104→        let seal: String = signer
105→            .nip44_decrypt(&gift_wrap.pubkey, &gift_wrap.content)
106→            .await?;
107→        let seal: Event = Event::from_json(seal)?;
108→        seal.verify_with_ctx(secp)?;
109→
110→        // Decrypt and parse rumor
111→        let rumor: String = signer.nip44_decrypt(&seal.pubkey, &seal.content).await?;
112→        let rumor: UnsignedEvent = UnsignedEvent::from_json(rumor)?;
113→
114→        // Ensure the rumor author matches the seal
115→        if rumor.pubkey != seal.pubkey {
116→            return Err(Error::SenderMismatch);
117→        }
118→
119→        Ok(Self {
120→            sender: seal.pubkey,
121→            rumor,
122→        })
123→    }
124→}
125→
126→/// Extract `rumor` from Gift Wrap event
127→#[inline]
128→#[cfg(feature = "std")]
129→pub async fn extract_rumor<T>(signer: &T, gift_wrap: &Event) -> Result<UnwrappedGift, Error>
130→where
131→    T: NostrSigner,
132→{
133→    UnwrappedGift::from_gift_wrap(signer, gift_wrap).await
134→}
135→
136→/// Make a seal
137→///
138→/// The `rumor` can be an [`EventBuilder`] or an [`UnsignedEvent`].
139→#[cfg(feature = "std")]
140→pub async fn make_seal<T>(
141→    signer: &T,
142→    receiver_pubkey: &PublicKey,
143→    // TODO: allow to pass a reference
144→    mut rumor: UnsignedEvent, // Don't take the `EventBuilder`, read note below.
145→) -> Result<EventBuilder, Error>
146→where
147→    T: NostrSigner,
148→{
149→    // Take an `UnsignedEvent` as rumor and not an `EventBuilder`!
150→    // May be useful to take an `EventBuilder` but it can create issues:
151→    // if a dev passes the same cloned `EventBuilder` to send the rumor to multiple users,
152→    // the final rumor will have different `created_at` timestamps, so different event IDs.
153→
154→    // Make sure that rumor has event ID
155→    rumor.ensure_id();
156→
157→    // Encrypt content
158→    let content: String = signer
159→        .nip44_encrypt(receiver_pubkey, &rumor.as_json())
160→        .await?;
161→
162→    // Compose builder
163→    Ok(EventBuilder::new(Kind::Seal, content)
164→        .custom_created_at(Timestamp::tweaked(RANGE_RANDOM_TIMESTAMP_TWEAK)))
165→}
